# This system is designed to manage and track the progress of tasks with dependencies.

from collections import defaultdict, deque

class TaskChain:
    def __init__(self):
        self.tasks = {}
        self.dependencies = defaultdict(list)
        self.completed_tasks = set()

    def add_task(self, task_id, description, dependencies=[]):
        if task_id in self.tasks:
            raise ValueError(f'Task {task_id} already exists.')
        self.tasks[task_id] = description
        for dep in dependencies:
            self.dependencies[task_id].append(dep)

    def mark_task_completed(self, task_id):
        if task_id not in self.tasks:
            raise ValueError(f'Task {task_id} does not exist.')
        if all(dep in self.completed_tasks for dep in self.dependencies[task_id]):
            self.completed_tasks.add(task_id)
        else:
            raise ValueError(f'Task {task_id} cannot be completed as its dependencies are not met.')

    def get_task_status(self, task_id):
        if task_id not in self.tasks:
            raise ValueError(f'Task {task_id} does not exist.')
        return 'Completed' if task_id in self.completed_tasks else 'Pending'

    def get_all_tasks(self):
        return self.tasks

    def get_completed_tasks(self):
        return self.completed_tasks

    def get_pending_tasks(self):
        return set(self.tasks.keys()) - self.completed_tasks

    def get_task_dependencies(self, task_id):
        if task_id not in self.tasks:
            raise ValueError(f'Task {task_id} does not exist.')
        return self.dependencies[task_id]

    def get_tasks_in_order(self):
        in_degree = {task: 0 for task in self.tasks}
        for task, deps in self.dependencies.items():
            for dep in deps:
                in_degree[dep] += 1

        queue = deque([task for task, degree in in_degree.items() if degree == 0])
        ordered_tasks = []

        while queue:
            task = queue.popleft()
            ordered_tasks.append(task)
            for dep in self.dependencies[task]:
                in_degree[dep] -= 1
                if in_degree[dep] == 0:
                    queue.append(dep)

        if len(ordered_tasks) != len(self.tasks):
            raise ValueError('Cycle detected in task dependencies.')

        return ordered_tasks

